import React, { useEffect, useState } from "react";
import DataTable from "react-data-table-component";
import { fetchAllMetaJobDescription } from "../../../components/services/CareerApi";
import { tableJobDescriptionPositionConstant } from "./tableJobDescriptionPositionConstant";
import { customStyles } from "../../../utils/tableCustomStyles";
import Select from 'react-select';
import { useParams } from "react-router-dom";
import GoBackComponent from "../../../utils/GoBackComponent";

const positonOptions = [
    { value: 'ALL', label: 'All' },
    { value: 'OPEN', label: 'Open' },
    { value: 'PUBLISH', label: 'Published' },
    { value: 'CLOSED', label: 'Closed' }
];

function JobDescriptionPositionList() {
    let { id } = useParams();
    const [rowData, setRowData] = useState([]);
    const [status, setStatus] = useState({ value: "ALL", label: "All" });
    const [perPage, setPerPage] = useState(10);
    const [loading, setLoading] = useState(false);
    const [totalRows, setTotalRows] = useState(0);

    useEffect(() => {
        fetchMetaJobDescriptionList(1, perPage);
    }, [status]);

    const fetchMetaJobDescriptionList = async (page, size) => {
        let data = {
            status: status?.value,
            jobDescriptionId: id,
            page: page,
            size: size
        }
        let response = await fetchAllMetaJobDescription(data);
        if (response?.code === 200) {
            setRowData(response?.results?.content);
            setLoading(false);
            setTotalRows(response?.results?.totalElements);
        }
    }

    const handlePageChange = page => {
        fetchMetaJobDescriptionList(page, perPage);
    };

    const handlePerRowsChange = async (newPerPage, page) => {
        setPerPage(newPerPage);
        fetchMetaJobDescriptionList(page, newPerPage);
    };

    const handleSelectChange = (data) => {
        setStatus(data);
    }

    return (
        <>
            <GoBackComponent goBackData={"career/job-description"} />
            <div className='row'>
                <div className="col-md-12 mb-3">
                    <div className="filterSection">
                        <div className="col-md-3">
                            <Select
                                options={positonOptions}
                                placeholder={"Filter by status"}
                                value={status}
                                onChange={handleSelectChange}
                                classNamePrefix="select"
                                styles={{
                                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                        const color = '#03a68059';
                                        return {
                                            ...styles,
                                            backgroundColor: isDisabled
                                                ? null
                                                : isSelected
                                                    ? '#03a68059'
                                                    : isFocused
                                                        ? '#03a68059'
                                                        : null,
                                            color: isDisabled
                                                ? '#ccc'
                                                : isSelected
                                                    ? color > 2
                                                        ? '#00374d'
                                                        : '#00374d'
                                                    : data.color,
                                            cursor: isDisabled ? 'not-allowed' : 'default',

                                            ':active': {
                                                ...styles[':active'],
                                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                                            },
                                        };
                                    },
                                }}
                            />
                        </div>
                    </div>
                </div>

                <div className="col2Large">
                    <DataTable
                        title="JD Position List"
                        columns={tableJobDescriptionPositionConstant(fetchMetaJobDescriptionList, id)}
                        data={rowData}
                        customStyles={customStyles}
                        //actions={actionButton()}
                        pagination
                        paginationPerPage={perPage}
                        pointerOnHover
                        fixedHeader
                        noContextMenu
                        fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                        progressPending={loading}
                        paginationServer
                        paginationTotalRows={totalRows}
                        onChangeRowsPerPage={handlePerRowsChange}
                        onChangePage={handlePageChange}
                        noDataComponent={
                            <div className="zdata pb-4" style={{marginTop: "40px"}}>
                                <div className="desc">
                                    <p>{"No open positions published"}</p>
                                </div>
                            </div>
                        }
                    />
                </div>
            </div>
        </>
    )
}

export default JobDescriptionPositionList;
